package com.hospital.management.controller.admin;import com.hospital.management.service.*;import com.hospital.management.service.impl.DepartmentServiceImpl;import com.hospital.management.util.RequestUtil;import javax.servlet.annotation.WebServlet;import javax.servlet.http.*;import java.io.IOException;
@WebServlet("/admin/departments/status")public class DepartmentStatusServlet extends HttpServlet{private final DepartmentService service;public DepartmentStatusServlet(){this(new DepartmentServiceImpl());}public DepartmentStatusServlet(DepartmentService s){service=s;}protected void doPost(HttpServletRequest q,HttpServletResponse r)throws IOException{Long id=Form.id(q.getParameter("departmentId"));String action=q.getParameter("action");if(id==null||!("activate".equals(action)||"deactivate".equals(action))){r.sendError(400);return;}ServiceResult<Void>x="activate".equals(action)?service.activateDepartment(id,RequestUtil.buildAuditContext(q)):service.deactivateDepartment(id,RequestUtil.buildAuditContext(q));String param=x.isSuccess()?"message="+action+"d":"error="+(x.getStatus()==ServiceResult.Status.CONFLICT?"activeDoctors":"operation");r.sendRedirect(q.getContextPath()+"/admin/departments?"+param);}}
